export function ProviderIcon({
  providerId,
  size = 14,
  className,
}: {
  providerId: string;
  size?: number;
  className?: string;
}) {
  const props = { size, className: cn("shrink-0", className) };

  switch (providerId) {
    case "openai":
    case "codex-cli":
      return <OpenAIIcon {...props} />;
    case "anthropic":
    case "claude-code":
      return <AnthropicIcon {...props} />;
    case "gemini":
    case "google":
    case "gemini-cli":
      return <GeminiIcon {...props} />;
    case "grok":
    case "xai":
    case "x-ai":
      return <XAIIcon {...props} />;
    case "deepseek":
      return <DeepSeekIcon {...props} />;
    case "mistral":
      return <MistralIcon {...props} />;
    case "ollama":
      return <OllamaIcon {...props} />;
    case "openrouter":
      return <OpenRouterIcon {...props} />;
    case "kimi-cli":
      return <MoonshotIcon {...props} />;
    case "qwen":
    case "qwen-code":
      return <QwenIcon {...props} />;
    case "opencode":
    case "custom":
      return <CustomAPIIcon {...props} />;
    default:
      return <CustomAPIIcon {...props} />;
  }
}
